/**
 * Email notification handler — formats and sends email notifications
 * in response to order lifecycle events.
 *
 * Follows the same EventBus subscription pattern as NotificationService.
 * Subscribes to order events and produces formatted email notifications.
 *
 * Depends on:
 * - EventBus (event system) for receiving order lifecycle events
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
} from '../events/event-types.js';
import type { OrderStatus } from '../models/order.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  id: string;
  to: string;
  from: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

const DEFAULT_FROM_ADDRESS = 'orders@taskflowpro.com';

let nextId = 1;

function generateEmailId(): string {
  return `email-${String(nextId++).padStart(4, '0')}`;
}

export function resetEmailIdCounter(): void {
  nextId = 1;
}

const STATUS_LABELS: Record<OrderStatus, string> = {
  pending: 'Pending',
  confirmed: 'Confirmed',
  shipped: 'Shipped',
  delivered: 'Delivered',
  cancelled: 'Cancelled',
};

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');
  private sentEmails: EmailMessage[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register event handlers for email notification triggers.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created — send confirmation email with order details.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);

    const itemRows = event.order.items
      .map(
        (item) =>
          `<tr><td>${item.name}</td><td>${item.quantity}</td><td>$${item.unitPrice.toFixed(2)}</td></tr>`,
      )
      .join('');

    const itemText = event.order.items
      .map((item) => `- ${item.name} x${item.quantity} @ $${item.unitPrice.toFixed(2)}`)
      .join('\n');

    const htmlBody = [
      `<h1>Order Confirmation</h1>`,
      `<p>Hi ${event.user.name},</p>`,
      `<p>Thank you for your order <strong>${event.order.id}</strong>.</p>`,
      `<table><thead><tr><th>Item</th><th>Qty</th><th>Price</th></tr></thead>`,
      `<tbody>${itemRows}</tbody></table>`,
      `<p><strong>Total: $${event.order.total.toFixed(2)}</strong></p>`,
    ].join('');

    const textBody = [
      `Order Confirmation`,
      ``,
      `Hi ${event.user.name},`,
      ``,
      `Thank you for your order ${event.order.id}.`,
      ``,
      `Items:`,
      itemText,
      ``,
      `Total: $${event.order.total.toFixed(2)}`,
    ].join('\n');

    this.sendEmail({
      to: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      htmlBody,
      textBody,
    });
  }

  /**
   * Handle order status change — send status update email.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update email for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const newLabel = STATUS_LABELS[event.newStatus as OrderStatus] ?? event.newStatus;
    const prevLabel = STATUS_LABELS[event.previousStatus as OrderStatus] ?? event.previousStatus;

    const htmlBody = [
      `<h1>Order Status Update</h1>`,
      `<p>Your order <strong>${event.order.id}</strong> has been updated.</p>`,
      `<p>Status: <em>${prevLabel}</em> &rarr; <strong>${newLabel}</strong></p>`,
    ].join('');

    const textBody = [
      `Order Status Update`,
      ``,
      `Your order ${event.order.id} has been updated.`,
      `Status: ${prevLabel} -> ${newLabel}`,
    ].join('\n');

    this.sendEmail({
      to: event.order.userId,
      subject: `Order ${event.order.id} — ${newLabel}`,
      htmlBody,
      textBody,
    });
  }

  /**
   * Send an email (in-memory for this demo).
   */
  private sendEmail(params: {
    to: string;
    subject: string;
    htmlBody: string;
    textBody: string;
  }): void {
    const email: EmailMessage = {
      id: generateEmailId(),
      to: params.to,
      from: DEFAULT_FROM_ADDRESS,
      subject: params.subject,
      htmlBody: params.htmlBody,
      textBody: params.textBody,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);
    this.logger.info(`Email sent: ${email.id} to ${email.to}`);
  }

  /**
   * Get all sent emails.
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Get emails for a specific recipient.
   */
  getEmailsForRecipient(recipient: string): EmailMessage[] {
    return this.sentEmails.filter((e) => e.to === recipient);
  }

  /**
   * Get the count of sent emails.
   */
  getSentEmailCount(): number {
    return this.sentEmails.length;
  }

  /**
   * Clear all sent emails (useful for testing).
   */
  clearEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  EmailNotificationHandler,
  resetEmailIdCounter,
} from '../../src/notifications/email-notification-handler.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
} from '../../src/events/event-types.js';

describe('EmailNotificationHandler', () => {
  let eventBus: EventBus;
  let handler: EmailNotificationHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    handler = new EmailNotificationHandler(eventBus);
    resetEmailIdCounter();
  });

  describe('order:created handler', () => {
    it('should send confirmation email on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.from).toBe('orders@taskflowpro.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');
      expect(emails[0]?.subject).toContain('order-1');
    });

    it('should include item details in email body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Widget');
      expect(email.htmlBody).toContain('Gadget');
      expect(email.htmlBody).toContain('$45.00');
      expect(email.textBody).toContain('Widget x2');
      expect(email.textBody).toContain('Gadget x1');
      expect(email.textBody).toContain('$45.00');
    });

    it('should include user name in email body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Bob');
      expect(email.textBody).toContain('Bob');
    });
  });

  describe('order:status-changed handler', () => {
    it('should send status update email on status change', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('order-1');
      expect(emails[0]?.subject).toContain('Confirmed');
    });

    it('should include previous and new status in email body', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Confirmed');
      expect(email.htmlBody).toContain('Shipped');
      expect(email.textBody).toContain('Confirmed');
      expect(email.textBody).toContain('Shipped');
    });

    it('should handle delivered status', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'delivered',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'shipped',
        newStatus: 'delivered',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.subject).toContain('Delivered');
      expect(email.textBody).toContain('Delivered');
    });

    it('should handle cancelled status', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'cancelled',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'cancelled',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.subject).toContain('Cancelled');
      expect(email.textBody).toContain('Cancelled');
    });
  });

  describe('email management', () => {
    it('should count sent emails', async () => {
      expect(handler.getSentEmailCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getSentEmailCount()).toBe(1);
    });

    it('should filter emails by recipient', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      expect(handler.getEmailsForRecipient('alice@example.com')).toHaveLength(1);
      expect(handler.getEmailsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear emails', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      handler.clearEmails();
      expect(handler.getSentEmailCount()).toBe(0);
    });

    it('should generate sequential email IDs', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const emails = handler.getSentEmails();
      expect(emails[0]?.id).toBe('email-0001');
      expect(emails[1]?.id).toBe('email-0002');
    });

    it('should provide both HTML and text bodies', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('<h1>');
      expect(email.textBody).not.toContain('<h1>');
    });
  });
});

